import{_ as l}from"./plugin-vue_export-helper-c27b6911.js";import{r as o,o as i,c,f as r,a as s,b as e,d as p,e as a}from"./app-045fd073.js";const t={},d=s("blockquote",null,[s("p",null,"Set the envrionment and boot the machine")],-1),u=a(`<h1 id="envrionment-setting" tabindex="-1"><a class="header-anchor" href="#envrionment-setting" aria-hidden="true">#</a> Envrionment Setting</h1><p>My Computer information (which is required):</p><ul><li>OS: Linux x86_64 (6.1.53-1-MANJARO)</li><li>CPU: 13th Gen Intel i5-13500H (16) @ 4.700GHz</li><li>GPU: Intel Raptor Lake-P [Iris Xe Graphics]</li><li>Memory: 16GB</li><li>Editor: VS Code</li><li>C Compiler: gcc(version 13.2.1) clang(version 16.0.6)</li><li>C++ Compiler: g++(version 13.2.1) clang++(version 16.0.6)</li><li>C/C++ build tools: cmake(version 3.27.6) xmake(version 2.8.3) make(version 4.4.1)</li><li>Rust: rustc 1.73.0-nightly</li><li>Python: Python 3.11.5</li><li>Java: openjdk 21 2023-09-19</li><li>Go: version go1.21.1 linux/amd64</li></ul><h2 id="how-to-build" tabindex="-1"><a class="header-anchor" href="#how-to-build" aria-hidden="true">#</a> How to build</h2><p>Run command below in your shell:</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">git</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">clone</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">https://gitee.com/ipads-lab/chcore-lab-v2.git</span></span>
<span class="line"><span style="color:#56B6C2;">cd</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">chcore-lab-v2</span></span>
<span class="line"><span style="color:#61AFEF;">make</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">build</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>and then it will pull a image from docker hub, which is called chcore_builder.</p><blockquote><p>If error like &quot;failed to add the host (veth28449b0) &lt;=&gt; sandbox (veth45f4af9) pair interfaces: operation not supported.&quot; occurs, try to restart your computer or docker</p></blockquote><p>Now, you&#39;ve already build a file named &quot;kernel.img&quot; in directory &quot;build/&quot;.</p><h2 id="how-to-run" tabindex="-1"><a class="header-anchor" href="#how-to-run" aria-hidden="true">#</a> How to run</h2><p>Simply run :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">make</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">qemu</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>to run <code>Chcore</code></p><blockquote><p>Note that there is no output, which is normal. It won&#39;t give any output until you finish lab1</p></blockquote><h2 id="how-to-debug" tabindex="-1"><a class="header-anchor" href="#how-to-debug" aria-hidden="true">#</a> How to debug</h2><p>You need install <code>gdb-multiarch</code> to debug. For example, in my manjaro, run :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">gdb-multiarch</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>If you&#39;re in Ubuntu, just run :</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#abb2bf;">sudo apt-get install gdb-multiarch</span></span>
<span class="line"><span style="color:#abb2bf;"></span></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>After installing, using two bash(or anything else such as <code>tmux</code>), one run :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">make</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">qemu-gdb</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>to activate qemu&#39;s gdb mode, the other run :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">make</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">gdb</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>to connect the remote target(i.e. the qemu&#39;s gdb mode).</p><p>If you see this, then it&#39;s success.</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20230901091127.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h2 id="how-to-edit-code" tabindex="-1"><a class="header-anchor" href="#how-to-edit-code" aria-hidden="true">#</a> How to edit code</h2><p>I strongly recommand <code>VS Code</code>, just <code>cd</code> into this directory and type <code>code .</code>, then you can use it to edit the code.</p><h1 id="machine-boot" tabindex="-1"><a class="header-anchor" href="#machine-boot" aria-hidden="true">#</a> Machine Boot</h1><p>The lab document is in <code>docs/</code>, follow it to finish the lab.</p><h2 id="pre" tabindex="-1"><a class="header-anchor" href="#pre" aria-hidden="true">#</a> Pre</h2><p>Modify <code>Makefile</code> like this :</p><div class="language-makefile line-numbers-mode" data-ext="makefile"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">qemu</span><span style="color:#ABB2BF;">:</span><span style="color:#E06C75;"> build</span></span>
<span class="line"><span style="color:#E5C07B;">	</span><span style="color:#98C379;">$(</span><span style="color:#E06C75;">V</span><span style="color:#98C379;">)$(</span><span style="color:#E06C75;">_QEMU</span><span style="color:#98C379;">)</span><span style="color:#E5C07B;"> </span><span style="color:#98C379;">$(</span><span style="color:#E06C75;">QEMU_OPTS</span><span style="color:#98C379;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#61AFEF;">qemu-gdb</span><span style="color:#ABB2BF;">:</span><span style="color:#E06C75;"> build</span></span>
<span class="line"><span style="color:#E5C07B;">	</span><span style="color:#98C379;">$(</span><span style="color:#E06C75;">V</span><span style="color:#98C379;">)$(</span><span style="color:#E06C75;">_QEMU</span><span style="color:#98C379;">)</span><span style="color:#E5C07B;"> -S -gdb tcp::</span><span style="color:#98C379;">$(</span><span style="color:#E06C75;">QEMU_GDB_PORT</span><span style="color:#98C379;">)</span><span style="color:#E5C07B;"> </span><span style="color:#98C379;">$(</span><span style="color:#E06C75;">QEMU_OPTS</span><span style="color:#98C379;">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>That would avoid run code but do not update it</p><h2 id="q1" tabindex="-1"><a class="header-anchor" href="#q1" aria-hidden="true">#</a> Q1</h2><blockquote><p>阅读 <code>_start</code> 函数的开头，尝试说明 ChCore 是如何让其中一个核首先进入初始化流程，并让其他核暂停执行的。</p></blockquote><ol><li>Read the cpu id from <code>mpidr_el1</code> register to the <code>x8</code> register</li><li>Get the low 8-bit value of the register <code>x8</code></li><li>Check if low 8-bit is <code>0</code>, if true, then jump to function <code>primary</code>, else, make a infnity loop to build a fence to stop others cores at this instruction</li><li>function <code>primary</code> will enter a initial procedure, including set the exception level to <code>EL1</code> and stack size, transfer control to the kernel</li></ol><p>for more: register <code>mpidr_el1</code> store the information of core, in multi-processor system, every processor has a unique value of <code>mpidr_el1</code>.</p><h2 id="m2" tabindex="-1"><a class="header-anchor" href="#m2" aria-hidden="true">#</a> M2</h2><blockquote><p>练习题 2：在 <code>arm64_elX_to_el1</code> 函数的 <code>LAB 1 TODO 1</code> 处填写一行汇编代码，获取 CPU 当前异常级别。</p></blockquote><div class="language-asm line-numbers-mode" data-ext="asm"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">mrs x9, CurrentEL</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20230904230236.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h2 id="m3" tabindex="-1"><a class="header-anchor" href="#m3" aria-hidden="true">#</a> M3</h2><p>Look at label <code>.Lno_gic_sr</code>, that is how to jump to <code>el1</code> from <code>el2</code>.</p><p>So we write code like this :</p><div class="language-asm line-numbers-mode" data-ext="asm"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">	adr x9, .Ltarget</span></span>
<span class="line"><span style="color:#ABB2BF;">	msr elr_el3, x9</span></span>
<span class="line"><span style="color:#ABB2BF;">	</span><span style="color:#C678DD;">mov</span><span style="color:#ABB2BF;"> x9, SPSR_ELX_DAIF | SPSR_ELX_EL1H</span></span>
<span class="line"><span style="color:#ABB2BF;">	msr spsr_el3, x9</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>to ensure our implementation is right, we use <code>gdb</code> below :</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20230905101732.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><p>we will see that it jump back <code>_start</code> from function <code>arm64_elX_to_el1</code></p><h2 id="q4" tabindex="-1"><a class="header-anchor" href="#q4" aria-hidden="true">#</a> Q4</h2><blockquote><p>结合此前 ICS 课的知识，并参考 <code>kernel.img</code> 的反汇编（通过 <code>aarch64-linux-gnu-objdump -S</code> 可获得），说明为什么要在进入 C 函数之前设置启动栈。如果不设置，会发生什么？</p></blockquote><p>We can see the assembly below :</p><div class="language-asm line-numbers-mode" data-ext="asm"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">   </span><span style="color:#C678DD;">80010</span><span style="color:#ABB2BF;">:	94001ffc 	</span><span style="color:#D19A66;">bl</span><span style="color:#ABB2BF;">	</span><span style="color:#C678DD;">88000</span><span style="color:#ABB2BF;"> &lt;arm64_elX_to_el1&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">   </span><span style="color:#C678DD;">80014</span><span style="color:#ABB2BF;">:	580000a0 	ldr	x0, </span><span style="color:#C678DD;">80028</span><span style="color:#ABB2BF;"> &lt;primary+</span><span style="color:#D19A66;">0x18</span><span style="color:#ABB2BF;">&gt;</span></span>
<span class="line"><span style="color:#ABB2BF;">   </span><span style="color:#C678DD;">80018</span><span style="color:#ABB2BF;">:	</span><span style="color:#C678DD;">91400400</span><span style="color:#ABB2BF;"> 	</span><span style="color:#C678DD;">add</span><span style="color:#ABB2BF;">	x0, x0, #</span><span style="color:#D19A66;">0x1</span><span style="color:#ABB2BF;">, </span><span style="color:#C678DD;">lsl</span><span style="color:#ABB2BF;"> #</span><span style="color:#C678DD;">12</span></span>
<span class="line"><span style="color:#ABB2BF;">   </span><span style="color:#FFFFFF;">8001c:</span><span style="color:#ABB2BF;">	9100001f 	</span><span style="color:#C678DD;">mov</span><span style="color:#ABB2BF;">	</span><span style="color:#D19A66;">sp</span><span style="color:#ABB2BF;">, x0</span></span>
<span class="line"><span style="color:#ABB2BF;">   </span><span style="color:#C678DD;">80020</span><span style="color:#ABB2BF;">:	</span><span style="color:#D19A66;">940020e2</span><span style="color:#ABB2BF;"> 	</span><span style="color:#D19A66;">bl</span><span style="color:#ABB2BF;">	883a8 &lt;init_c&gt;</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>note that <code>=boot_cpu_stack</code> is <code>*0x80028</code>(i.e. 0x00088980), and <code>INIT_STACK_SIZE</code> is 0x1000(i.e. 0x1, lsl #12)</p><p>Because <code>init_c</code> is a function which require a stack frame. That&#39;s why we should initial the stack pointer and allocate stack space.</p>`,55),h={href:"http://rcore-os.cn/rCore-Tutorial-Book-v3/chapter1/5support-func-call.html#jump-practice",target:"_blank",rel:"noopener noreferrer"},m=a(`<h2 id="q5" tabindex="-1"><a class="header-anchor" href="#q5" aria-hidden="true">#</a> Q5</h2><blockquote><p>在实验 1 中，其实不调用 <code>clear_bss</code> 也不影响内核的执行，请思考不清理 <code>.bss</code> 段在之后的何种情况下会导致内核无法工作。</p></blockquote><p>Anser from GPT:</p><blockquote><p>当不清零 <code>.bss</code> 段时，未显式初始化的全局变量和静态变量的初始值将是未定义的。这可能导致以下问题和错误：</p><ol><li>未定义的行为：访问未初始化的变量可能导致未定义的行为。这包括读取随机的内存值、产生不可预测的结果以及可能导致程序崩溃或错误的行为。</li><li>依赖于零值的假设：在程序设计中，有时会假设未初始化的全局变量或静态变量的初始值为零。如果这些变量的初始值不是零，那么这些假设就会被破坏，可能导致程序逻辑错误或不一致。</li><li>安全问题：如果未初始化的变量被认为是零值，而实际上它们存储了其他敏感信息，可能会引发安全问题。例如，如果未初始化的变量被用于存储密码、密钥或其他敏感数据，那么不清零可能导致这些敏感信息泄露。</li><li>跨平台兼容性问题：不同的编译器和操作系统对未初始化变量的处理可能不同。在某些平台上，编译器或操作系统可能为未初始化变量提供默认的零值，而在其他平台上可能不会。因此，不清零 <code>.bss</code> 段可能导致在不同的平台上出现不一致的行为，影响跨平台的兼容性。</li></ol></blockquote><h2 id="m6" tabindex="-1"><a class="header-anchor" href="#m6" aria-hidden="true">#</a> M6</h2><div class="language-c line-numbers-mode" data-ext="c"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#C678DD;">void</span><span style="color:#ABB2BF;"> </span><span style="color:#61AFEF;">uart_send_string</span><span style="color:#ABB2BF;">(</span><span style="color:#C678DD;">char</span><span style="color:#E06C75;"> </span><span style="color:#C678DD;">*</span><span style="color:#E06C75;font-style:italic;">str</span><span style="color:#ABB2BF;">)</span></span>
<span class="line"><span style="color:#ABB2BF;">{</span></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">        /* LAB 1 TODO 3 BEGIN */</span></span>
<span class="line"></span>
<span class="line"><span style="color:#ABB2BF;">        </span><span style="color:#C678DD;">while</span><span style="color:#ABB2BF;"> (</span><span style="color:#C678DD;">*</span><span style="color:#ABB2BF;">str </span><span style="color:#C678DD;">!=</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">&#39;</span><span style="color:#56B6C2;">\\0</span><span style="color:#98C379;">&#39;</span><span style="color:#ABB2BF;">) {</span></span>
<span class="line"><span style="color:#ABB2BF;">                </span><span style="color:#61AFEF;">early_uart_send</span><span style="color:#ABB2BF;">((</span><span style="color:#C678DD;">unsigned</span><span style="color:#ABB2BF;"> </span><span style="color:#C678DD;">int</span><span style="color:#ABB2BF;">)(</span><span style="color:#C678DD;">*</span><span style="color:#ABB2BF;">str));</span></span>
<span class="line"><span style="color:#ABB2BF;">                str</span><span style="color:#C678DD;">++</span><span style="color:#ABB2BF;">;</span></span>
<span class="line"><span style="color:#ABB2BF;">        }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#7F848E;font-style:italic;">        /* LAB 1 TODO 3 END */</span></span>
<span class="line"><span style="color:#ABB2BF;">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20230905104428.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure><h2 id="m7" tabindex="-1"><a class="header-anchor" href="#m7" aria-hidden="true">#</a> M7</h2><p>I wrote this in first</p><div class="language-asm line-numbers-mode" data-ext="asm"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">orr x8, x8, #</span><span style="color:#D19A66;">0x82f</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>which enable all flags.</p><p>However, we can see that below here:</p><div class="language-asm line-numbers-mode" data-ext="asm"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">	bic     x8, x8, #SCTLR_EL1_A</span></span>
<span class="line"><span style="color:#ABB2BF;">	bic     x8, x8, #SCTLR_EL1_SA0</span></span>
<span class="line"><span style="color:#ABB2BF;">	bic     x8, x8, #SCTLR_EL1_SA</span></span>
<span class="line"><span style="color:#ABB2BF;">	orr     x8, x8, #SCTLR_EL1_nAA</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>it reminds us that we should just enable one flag here, i.e. flag <code>M</code>, so the correct code is :</p><div class="language-asm line-numbers-mode" data-ext="asm"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#ABB2BF;">orr x8, x8, #SCTLR_EL1_M</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h1 id="how-to-grade" tabindex="-1"><a class="header-anchor" href="#how-to-grade" aria-hidden="true">#</a> How to Grade</h1><p>Remember to install <code>expect</code>， in Manjaro you can :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">yay</span><span style="color:#ABB2BF;"> </span><span style="color:#D19A66;">-S</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">expect</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>then type :</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="shiki one-dark-pro" style="background-color:#282c34;" tabindex="0"><code><span class="line"><span style="color:#61AFEF;">make</span><span style="color:#ABB2BF;"> </span><span style="color:#98C379;">grade</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>you will see something like this:</p><figure><img src="https://virgil-civil-1311056353.cos.ap-shanghai.myqcloud.com/img/20230907150335.png" alt="image.png" tabindex="0" loading="lazy"><figcaption>image.png</figcaption></figure>`,22);function y(b,B){const n=o("ExternalLinkIcon");return i(),c("div",null,[d,r("more"),u,s("p",null,[e("more details in "),s("a",h,[e("rCore"),p(n)])]),m])}const x=l(t,[["render",y],["__file","Chcore-lab0-env.html.vue"]]);export{x as default};
